#include <stdio.h>
#include <stdlib.h>
#define INF 1000000000
#define MAX 100000

// Structure to represent a graph edge
typedef struct Edge {
    int src, dest, weight;
} Edge;

// Structure to represent a graph
typedef struct Graph {
    int V, E;
    Edge* edge;
} Graph;

// Function to create a graph
Graph* createGraph(int V, int E) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->V = V;    graph->E = E;
    graph->edge = (Edge*) malloc(E * sizeof(Edge));
    return graph;
}

// Function to find the vertex with minimum key value, from the set of vertices not yet included in MST
int minKey(int* key, int* mstSet, int V) {
    int min_val = INF, min_index;
    for (int v = 0; v < V; v++)
        if (key[v] < min_val && mstSet[v] == 0)
            min_val = key[v], min_index = v;
    return min_index;
}

// Function to construct MST using Prim's algorithm
void primMST(Graph* graph) {
    int* key = (int*) malloc(graph->V * sizeof(int));
    int* parent = (int*) malloc(graph->V * sizeof(int));
    int* mstSet = (int*) malloc(graph->V * sizeof(int));
    int i, u, v, w, x, y;
    for (i = 0; i < graph->V; i++)
        key[i] = INF, mstSet[i] = 0;
    key[0] = 0;
    parent[0] = -1;
    for (i = 0; i < graph->V - 1; i++) {
        u = minKey(key, mstSet, graph->V);
        mstSet[u] = 1;
        for (int j = 0; j < graph->E; j++) {
            v = graph->edge[j].dest;
            w = graph->edge[j].weight;
            if (graph->edge[j].src == u && mstSet[v] == 0 && w < key[v]) {
                parent[v] = u;
                key[v] = w;
            }
        }
    }
    printf("Edges in the MST:\n");
    int sum = 0;
    for (i = 1; i < graph->V; i++) {
        printf("%d -- %d == %d\n", parent[i], i, key[i]);
        sum += key[i];
    }
    printf("Sum of weights of the edges of the MST: %d\n", sum);
}

int main() {
    int V, E;
    scanf("%d %d", &V, &E);
    Graph* graph = createGraph(V, E);
    for (int i = 0; i < E; i++)
        scanf("%d %d %d", &graph->edge[i].src, &graph->edge[i].dest, &graph->edge[i].weight);
    primMST(graph);
    return 0;
}

