class Solution {
    spanningTree(V, adj) {
        let pq = [];
        let vis = new Array(V).fill(0);
        pq.push([0, 0]);
        pq.sort((a, b) => a[0] - b[0]);
        let sum = 0;
        while (pq.length > 0) {
            let [wt, node] = pq.shift();
            if (vis[node] === 1) continue;
            vis[node] = 1;
            sum += wt;
            for (let i = 0; i < adj[node].length; i++) {
                let [adjNode, edW] = adj[node][i];
                if (vis[adjNode] === 0) {
                    pq.push([edW, adjNode]);
                    pq.sort((a, b) => a[0] - b[0]);
                }
            }
        }
        return sum;
    }
}

let V = 5;
let edges = [[0, 1, 2], [0, 2, 1], [1, 2, 1], [2, 3, 2], [3, 4, 1], [4, 2, 2]];
let adj = Array(V).fill().map(() => []);
for (let i = 0; i < edges.length; i++) {
    let [u, v, w] = edges[i];
    adj[u].push([v, w]);
    adj[v].push([u, w]);
}

let obj = new Solution();
let sum = obj.spanningTree(V, adj);
console.log("The sum of all the edge weights: ", sum);
